#include<bits/stdc++.h>
using namespace std;
int a[6010],b[6010],c[6010];
int dp[2][30010],p[3];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d",&a[i],&b[i],&c[i]);
    }
    memset(dp,0x3f,sizeof(dp));
    p[0]=0;
    p[1]=1;
    dp[p[0]][0]=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=0;j<=30003;j++)
        {
            if(a[i]!=0&&j>=a[i])
            {
                dp[p[1]][j]=min(dp[p[1]][j],dp[p[0]][j-a[i]]);
            }
            if(b[i]!=0)
            {
                dp[p[1]][j]=min(dp[p[1]][j],dp[p[0]][j]+b[i]);
            }
            if(c[i]!=0&&j>=c[i])
            {
                dp[p[1]][j]=min(dp[p[1]][j],dp[p[0]][j-c[i]]+c[i]);
            }
        }
        swap(p[1],p[0]);
        memset(dp[p[1]],0x3f,sizeof(dp[p[1]]));
    }
    int ans=INT_MAX;
    for(int i=0;i<=30000;i++)
    {
        ans=min(ans,max(i,dp[p[0]][i]));
    }
    printf("%d",ans);
    return 0;
}
